Actionscript.script:
// ============================
// Tween 类定义
// ============================
function Tween(target, startAlpha, endAlpha, duration) {
    this.target = target;
    this.startAlpha = startAlpha;
    this.endAlpha = endAlpha;
    this.duration = duration;
    this.elapsed = 0;
    this.visibleAfter = endAlpha > 0;

    // 如果从透明度为0开始并且目标透明度大于0，设置可见
    if (this.startAlpha == 0 && this.endAlpha > 0) {
        this.target._visible = true;
    }
}

Tween.prototype.update = function(delta) {
    this.elapsed += delta;
    var t = this.elapsed / this.duration;
    if (t >= 1) {
        t = 1;
        this.target._alpha = this.endAlpha;
        if (this.endAlpha == 0) {
            this.target._visible = false;
        }
        return true; // Tween 完成
    }
    this.target._alpha = this.startAlpha + (this.endAlpha - this.startAlpha) * t;
    return false; // Tween 未完成
};

// ============================
// TweenManager 类定义
// ============================

var _this = this;
function TweenManager() {
    this.tweens = [];

    // 创建一个空的影片剪辑，挂载到当前环境
    this.tweenClip = _this.createEmptyMovieClip("tweenManagerClip", _this.getNextHighestDepth());

    // 绑定 onEnterFrame 到空影片剪辑
    var self = this; // 保存当前 TweenManager 的引用
    this.tweenClip.onEnterFrame = function() {
        self.update(); // 调用 TweenManager 的 update 方法
    };
}

// 添加一个 Tween 到管理器
TweenManager.prototype.addTween = function(tween) {
    this.tweens.push(tween);
};

// 更新所有 Tween
TweenManager.prototype.update = function() {
    var completedTweens = [];
    for (var i = 0; i < this.tweens.length; i++) {
        var tween = this.tweens[i];
        var done = tween.update(1); // 假设每帧时间增量为 1
        if (done) {
            completedTweens.push(i);
        }
    }
    // 移除已完成的 Tweens
    for (var i = completedTweens.length - 1; i >= 0; i--) {
        this.tweens.splice(completedTweens[i], 1);
    }
};

// 销毁 TweenManager 时清理空影片剪辑
TweenManager.prototype.destroy = function() {
    this.tweenClip.removeMovieClip();
};

// ============================
// 初始化 TweenManager
// ============================
var tweenManager = new TweenManager();

// ============================
// 层级管理代码
// ============================

// 定义层级数组
var layers = [];

// 当前激活的层级
var currentActiveLayer = null;

