baseRoofLayer.name = "基地屋顶";
baseRoofLayer.components = [this.基地屋顶];
baseRoofLayer.npcs = [];
baseRoofLayer.selectableProperty = "基地屋顶可选";
layers.push(baseRoofLayer);

// 基地一层层级
