firstFloorLayer.name = "基地一层";
firstFloorLayer.components = [this.基地大厅, this.佣兵酒吧, this.基地车库, this.基地门口, this.医务室, this.宿舍];
firstFloorLayer.npcs = [
    { avatar: this.king头像, name: "king头像" },
    { avatar: this.boy头像, name: "boy头像" },
    { avatar: this.pig头像, name: "pig头像" },
    { avatar: this.冷兵器商人头像, name: "冷兵器商人头像" },
    { avatar: this.杀马特头像, name: "杀马特头像" },
    { avatar: this.酒保头像, name: "酒保头像" },
    { avatar: this.舞女头像, name: "舞女头像" },
    { avatar: this.格格巫头像, name: "格格巫头像" },
    { avatar: this.丽丽丝头像, name: "丽丽丝头像" },
    { avatar: this.黑铁会外交部长头像, name: "黑铁会外交部长头像" },
    { avatar: this.宝石线人头像, name: "宝石线人头像" },
    { avatar: this.前治安官头像, name: "前治安官头像" },
    { avatar: this.幸存老兵头像, name: "幸存老兵头像" },
    { avatar: this.学生妹头像, name: "学生妹头像" }
];
firstFloorLayer.selectableProperty = "基地一层可选";
layers.push(firstFloorLayer);

// 地下一层层级
var basement1Layer = {};
basement1Layer.name = "地下一层";
basement1Layer.components = [this.地下一层, this.健身房, this.武器库];
basement1Layer.npcs = [
    { avatar: this.andy头像, name: "andy头像" },
    { avatar: this.thegirl头像, name: "thegirl头像" },
    { avatar: this.shopgirl头像, name: "shopgirl头像" },
    { avatar: this.blue头像, name: "blue头像" },
    { avatar: this.小F头像, name: "小F头像" }
];
basement1Layer.selectableProperty = "地下一层可选";
layers.push(basement1Layer);

// 地下二层层级
var basement2Layer = {};
basement2Layer.name = "地下二层";
basement2Layer.components = [this.走廊, this.食堂];
basement2Layer.npcs = [];
basement2Layer.selectableProperty = "地下二层可选";
layers.push(basement2Layer);

// 地下水层级
var undergroundWaterLayer = {};
undergroundWaterLayer.name = "地下水";
undergroundWaterLayer.components = [this.地下水];
undergroundWaterLayer.npcs = [];
undergroundWaterLayer.selectableProperty = "地下水可选";
layers.push(undergroundWaterLayer);

// 定义通用的透明度设置函数
function setTransparency(targets, targetAlpha, duration) {
    tweenAlpha(targets, targetAlpha, duration);
}

// 定义透明度渐变函数，利用 TweenManager
function tweenAlpha(targets, targetAlpha, duration) {
    for (var i = 0; i < targets.length; i++) {
        var mc = targets[i];
        var tween = new Tween(mc, mc._alpha, targetAlpha, duration);
        tweenManager.addTween(tween);
    }
}

// 初始化层级状态
function initializeLayers() {
    for (var i = 0; i < layers.length; i++) {
        var layer = layers[i];
        // 设置组件半透明可见
        setTransparency(layer.components, 50, 5);
        for (var j = 0; j < layer.components.length; j++) {
            var component = layer.components[j];
            component.gotoAndStop(1); // 确保组件显示在初始状态
        }
        // 设置 NPC 头像透明度
        var npcAvatars = [];
        for (var k = 0; k < layer.npcs.length; k++) {
            var npcAvatar = layer.npcs[k].avatar;
            npcAvatar.gotoAndStop(1); // 确保NPC头像显示在初始状态
            npcAvatars.push(npcAvatar);
        }
        setTransparency(npcAvatars, 80, 5);
        // 设置可选属性为 false
        this[layer.selectableProperty] = false;
    }
    // 取消当前激活的层级
    currentActiveLayer = null;
    // 设置所有房间的 rollover 事件
    attachRollOverEvents();
}

// 激活层级函数
function activateLayer(activeLayer, activeRoom) {
    if (currentActiveLayer != null && currentActiveLayer != activeLayer) {
        // 如果有其他层级被激活，先取消其激活状态
        deactivateCurrentLayer();
    }

    currentActiveLayer = activeLayer;

    // 设置激活层级的组件和 NPC 头像全不透明
    var targets = [];
    for (var j = 0; j < activeLayer.components.length; j++) {
        targets.push(activeLayer.components[j]);
    }
    for (var k = 0; k < activeLayer.npcs.length; k++) {
        targets.push(activeLayer.npcs[k].avatar);
    }
    setTransparency(targets, 100, 5);

    /*
        // 将激活层级的所有房间移到最顶层（假设使用swapDepths方法）
        for (var j = 0; j < activeLayer.components.length; j++) {
            activeLayer.components[j].swapDepths(_root.getNextHighestDepth());
        }
    */

    // 高亮当前房间
    activeRoom.gotoAndStop(2);

    // 设置可选属性为 true
    this[activeLayer.selectableProperty] = true;

    // 移除所有房间的 rollover 事件
    removeRollOverEvents();

    // 为当前激活层级的房间添加 rollout 事件
    attachRollOutEvents(activeLayer);
}

// 取消激活当前层级
function deactivateCurrentLayer() {
    if (currentActiveLayer == null) return;

    var layer = currentActiveLayer;

    // 设置激活层级的组件和 NPC 头像半透明
    var targets = [];
    for (var j = 0; j < layer.components.length; j++) {
        targets.push(layer.components[j]);
    }
    for (var k = 0; k < layer.npcs.length; k++) {
        targets.push(layer.npcs[k].avatar);
    }
    setTransparency(targets, 50, 5);
    for (var j = 0; j < layer.components.length; j++) {
        layer.components[j].gotoAndStop(1); // 恢复组件初始状态
    }
    for (var k = 0; k < layer.npcs.length; k++) {
        layer.npcs[k].avatar.gotoAndStop(1); // 恢复NPC头像初始状态
    }

    // 设置可选属性为 false
    this[layer.selectableProperty] = false;

    // 重新绑定所有房间的 rollover 事件
    attachRollOverEvents();

    // 取消 rollout 事件
    removeRollOutEvents(layer);

    currentActiveLayer = null;
}

// 设置房间的 rollover 事件
function attachRollOverEvents() {
    for (var i = 0; i < layers.length; i++) {
        var layer = layers[i];
        for (var j = 0; j < layer.components.length; j++) {
            var roomClip = layer.components[j];
            // 避免重复绑定
            roomClip.onRollOver = function() {
                if (currentActiveLayer == null) {
                    activateLayer(this.layer, this);
                }
            };
        }
    }
}

// 移除所有房间的 rollover 事件
function removeRollOverEvents() {
    for (var i = 0; i < layers.length; i++) {
        var layer = layers[i];
        for (var j = 0; j < layer.components.length; j++) {
            var roomClip = layer.components[j];
            roomClip.onRollOver = null;
        }
    }
}

// 为激活层级的房间添加 rollout 事件
function attachRollOutEvents(layer) {
    for (var j = 0; j < layer.components.length; j++) {
        var roomClip = layer.components[j];
        roomClip.onRollOut = function() {
            // 取消高亮当前房间
            this.gotoAndStop(1);
            // 取消激活层级
            deactivateCurrentLayer();
        };
    }
}

// 取消激活层级的 rollout 事件
function removeRollOutEvents(layer) {
    if (layer == null) return;
    for (var j = 0; j < layer.components.length; j++) {
        var roomClip = layer.components[j];
        roomClip.onRollOut = null;
    }
}

// 设置每个房间的关联层级
for (var i = 0; i < layers.length; i++) {
    var layer = layers[i];
    for (var j = 0; j < layer.components.length; j++) {
        layer.components[j].layer = layer; // 关联房间与层级
    }
}

// 初始化层级状态
initializeLayers();

// 处理鼠标移动事件，仅在没有激活层级时进行碰撞检测
_root.onMouseMove = function() {
    if (currentActiveLayer != null) {
        // 当前有层级被激活，忽略全局鼠标移动事件
        return;
    }

    var isOverRoom = false;
    for (var i = 0; i < layers.length; i++) {
        var layer = layers[i];
        for (var j = 0; j < layer.components.length; j++) {
            var roomClip = layer.components[j];
            if (roomClip.hitTest(_root._xmouse, _root._ymouse, true)) {
                isOverRoom = true;
                break;
            }
        }
        if (isOverRoom) {
            break;
        }
    }
    if (!isOverRoom) {
        // 鼠标不在任何房间上，恢复初始状态
        initializeLayers();
    }
};

function 地图标识() {
    设置区域透明度();
    设置区域可选状态();
    设置NPC头像显示();
    设置NPC闪光提示();
}

function 设置区域透明度() {
    // 基地屋顶
    this.基地屋顶._alpha = 50;

    // 基地一层
    var 基地一层区域 = [
        this.基地大厅, this.佣兵酒吧, this.基地车库, 
        this.基地门口, this.医务室, this.宿舍
    ];
    for (var i = 0; i < 基地一层区域.length; i++) {
