    // 地下一层
    var 地下一层区域 = [this.地下一层, this.健身房, this.武器库];
    for (var i = 0; i < 地下一层区域.length; i++) {
        地下一层区域[i]._alpha = 50;
    }

    // 地下二层
    var 地下二层区域 = [this.走廊, this.食堂];
    for (var i = 0; i < 地下二层区域.length; i++) {
        地下二层区域[i]._alpha = 50;
    }

    // 地下水
    this.地下水._alpha = 50;
}

function 设置区域可选状态() {
    var 区域可选 = ["基地屋顶", "基地一层", "地下一层", "地下二层", "地下水"];
    for (var i = 0; i < 区域可选.length; i++) {
        this[区域可选[i] + "可选"] = false;
    }
}

function 设置NPC头像显示() {
    // 基地一层 NPC
    var 一层NPC头像 = [
        "king头像", "boy头像", "pig头像", "冷兵器商人头像",
        "杀马特头像", "酒保头像", "舞女头像", "格格巫头像",
        "丽丽丝头像"
    ];
    for (var i = 0; i < 一层NPC头像.length; i++) {
        this[一层NPC头像[i]]._alpha = 80;
    }

    // 动态任务相关头像
    设置任务相关头像("黑铁会外交部长头像", 69);
    设置任务相关头像("宝石线人头像", 42);
    设置任务相关头像("前治安官头像", 22);
    设置任务相关头像("幸存老兵头像", 19);
    设置任务相关头像("学生妹头像", 40);

    // 地下一层 NPC
    var 地下一层NPC头像 = [
        "andy头像", "thegirl头像", "shopgirl头像", 
        "blue头像", "小F头像"
    ];
    for (var i = 0; i < 地下一层NPC头像.length; i++) {
        this[地下一层NPC头像[i]]._alpha = 80;
    }
}

function 设置任务相关头像(头像名, 任务进度) {
    if (_root.主线任务进度 < 任务进度) {
        this[头像名]._visible = 0;
    } else {
        this[头像名]._visible = 1;
        this[头像名]._alpha = 80;
    }
}

function 设置NPC闪光提示() {
    var NPC闪光 = [
        "Pig_闪光提示", "Boy_闪光提示", "King_闪光提示",
        "The Girl_闪光提示", "Andy Law_闪光提示", "Shop Girl_闪光提示",
        "Blue_闪光提示", "酒保_闪光提示", "格格巫_闪光提示", "丽丽丝_闪光提示",
        "小F_闪光提示", "冷兵器商人_闪光提示", "宝石线人_闪光提示",
        "学生妹_闪光提示", "幸存老兵_闪光提示", "前治安官_闪光提示",
        "黑铁会外交部长_闪光提示", "舞女_闪光提示", "杀马特_闪光提示"
    ];
    for (var i = 0; i < NPC闪光.length; i++) {
        this[NPC闪光[i]]._visible = 0;
    }

    for (var i = 0; i < _root.tasks_to_do.length; i++) {
        if (_root.taskFinished(i)) {
            var npc闪光 = _root.getTaskData(_root.tasks_to_do[i].id).finish_npc + "_闪光提示";
            this[npc闪光]._visible = 1;
        }
    }
}

